-- ---------------------------------------------------------- Tabel structuur voor tabel behandelaars-- --------------------------------------------------------DROP TABLE IF EXISTS behandelaars;CREATE TABLE behandelaars (behandelaar_id smallint(11) NOT NULL auto_increment,beh_user_name varchar(20) NOT NULL default '',beh_emailadres varchar(35) NOT NULL default '',beh_voornaam varchar(20) NOT NULL default 'voornaam',beh_achternaam varchar(30) NOT NULL default 'achternaam',beh_paswoord varchar(50) NOT NULL default '',beh_remote_addr varchar(20) NOT NULL default '',beh_confirm_hash varchar(50) NOT NULL default '',beh_is_confirmed smallint(4) default NULL,beh_date_created date default NULL,beh_gebdat date NOT NULL default '0000-00-00',beh_gender smallint(3) default NULL,beh_vorm smallint(4) default '0',-- 0= huisarts, 1= arts, 2= psychotherapeut, 3= MaWe, 4= verpleegk, 5= , 6= beh_straat varchar(50) NOT NULL default '',beh_huisnum varchar(10) NOT NULL default '',beh_postcode varchar(10) NOT NULL default '',beh_stad varchar(40) NOT NULL default '',beh_foon varchar(30) NOT NULL default '',databasis varchar(4) NOT NULL default 'nl',PRIMARY KEY (behandelaar_id),KEY beh_user_name (beh_user_name)) TYPE=MyISAM AUTO_INCREMENT=100 ;-- Gegevens worden uitgevoerd voor tabel behandelaarsINSERT INTO `behandelaars` ( `behandelaar_id` , `beh_user_name` , `beh_emailadres` , `beh_voornaam` , `beh_achternaam` , `beh_paswoord` , `beh_remote_addr` , `beh_confirm_hash` , `beh_is_confirmed` , `beh_date_created` , `beh_gebdat` , `beh_gender` , `beh_vorm` , `beh_straat` , `beh_huisnum` , `beh_postcode` , `beh_stad` , `beh_foon` , `databasis` ) VALUES (5, 'admin', 'info@helpdisk.nl', 'Hans', 'West', '9e94b15ed312fa42232fd87a55db0d39', '213.148.230.117', 'efbc0ac03d6f5a6bd12de3802fd793fb', 1, '2007-11-15', '1959-01-27', NULL, 0, 'Billitonkade', '170', '3531TN', 'Utrecht', '030-2944440', 'nl');